//series-parser-helpers.js
import { utils } from '../utils/zcutils.js';
import { charttypenames } from './main-zc-init.js';
import { getDistinct } from '../utils/zcutils.js';
import { ZC_PLUGGABLE_VIZ } from './main-zc-init.js';

export function getAllSeriesTypes(userData) {
    let data = userData.seriesdata;
    if (!data || !data.chartdata) {
        return [];
    }

    let globalSeriesType = data.type || 'bar',
        chartNames = [],
        _addChartType = series => {
            let type = series.type || globalSeriesType,
                chartName;

            if (typeof type === 'number') {
                //Trash
                chartName = charttypenames.get(type);
            } else {
                chartName = type.toLowerCase();
            }

            chartNames.push(chartName);
        },
        facetRendering = userData.facets;

    if (facetRendering) {
        hierarchyTraverse(data.chartdata, _addChartType);
    } else {
        data.chartdata.forEach(_addChartType);
    }

    return chartNames;
}
utils.getAllSeriesTypes = getAllSeriesTypes;

function hierarchyTraverse(data, callback) {
    data.forEach(_ => {
        callback(_);
        if (_.data) {
            hierarchyTraverse(_.data, callback);
        }
    });
}

export function getCustomPluggedChartTypes(chart, data){
    let types = chart.distinctChartTypes || getDistinct(getAllSeriesTypes(data)),
    pluginTypes = new Array(0);
    types.map(d => {
        if(ZC_PLUGGABLE_VIZ._types[d]){
            chart.pluginChart = true;
            pluginTypes.push(d);
        }
    })
    return pluginTypes;
}
